package ugsync.org.apache.ranger.usergroupsync;

public class UserGroupSync implements Runnable { private static final Logger LOG = Logger . getLogger ( UserGroupSync . class ) ; private boolean shutdownFlag = false ; private UserGroupSink ugSink = null ; private UserGroupSource ugSource = null ; public static void main ( String [ ] args ) { UserGroupSync userGroupSync = new UserGroupSync ( ) ; userGroupSync . run ( ) ; } public void run ( ) { try { long sleepTimeBetweenCycleInMillis = UserGroupSyncConfig . getInstance ( ) . getSleepTimeInMillisBetweenCycle ( ) ; boolean initDone = false ; while ( ! initDone ) { try { ugSink = UserGroupSyncConfig . getInstance ( ) . getUserGroupSink ( ) ; LOG . info ( "initializing sink: " + ugSink . getClass ( ) . getName ( ) ) ; ugSink . init ( ) ; ugSource = UserGroupSyncConfig . getInstance ( ) . getUserGroupSource ( ) ; LOG . info ( "initializing source: " + ugSource . getClass ( ) . getName ( ) ) ; ugSource . init ( ) ; LOG . info ( "Begin: initial load of user/group from source==>sink" ) ; ugSource . updateSink ( ugSink ) ; LOG . info ( "End: initial load of user/group from source==>sink" ) ; initDone = true ; LOG . info ( "Done initializing user/group source and sink" ) ; } catch ( Throwable t ) { LOG . error ( "Failed to initialize UserGroup source/sink. Will retry after " + sleepTimeBetweenCycleInMillis + " milliseconds. Error details: " , t ) ; try { LOG . debug ( "Sleeping for [" + sleepTimeBetweenCycleInMillis + "] milliSeconds" ) ; Thread . sleep ( sleepTimeBetweenCycleInMillis ) ; } catch ( Exception e ) { LOG . error ( "Failed to wait for [" + sleepTimeBetweenCycleInMillis + "] milliseconds before attempting to initialize UserGroup source/sink" , e ) ; } } } boolean forceSync = false ; while ( ! shutdownFlag ) { try { LOG . debug ( "Sleeping for [" + sleepTimeBetweenCycleInMillis + "] milliSeconds" ) ; Thread . sleep ( sleepTimeBetweenCycleInMillis ) ; } catch ( InterruptedException e ) { LOG . error ( "Failed to wait for [" + sleepTimeBetweenCycleInMillis + "] milliseconds before attempting to synchronize UserGroup information" , e ) ; } try { syncUserGroup ( forceSync ) ; forceSync = false ; } catch ( Throwable t ) { LOG . error ( "Failed to synchronize UserGroup information. Error details: " , t ) ; forceSync = true ; } } } catch ( Throwable t ) { LOG . error ( "UserGroupSync thread got an error" , t ) ; } finally { LOG . info ( "Shutting down the UserGroupSync thread" ) ; } } private void syncUserGroup ( boolean forceSync ) throws Throwable { UserGroupSyncConfig config = UserGroupSyncConfig . getInstance ( ) ; try { if ( config . isUserSyncEnabled ( ) ) { if ( forceSync || ugSource . isChanged ( ) ) { LOG . info ( "Begin: update user/group from source==>sink" ) ; ugSource . updateSink ( ugSink ) ; LOG . info ( "End: update user/group from source==>sink" ) ; } else { LOG . debug ( "UserGroupSource: no change found for synchronization." ) ; } } } catch ( Throwable t ) { LOG . error ( "Failed to sync user/group : " , t ) ; } } }